  ('fire-eq-tech-moex-03195', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「防焰性能試驗基準」規定，防焰物品或其材料之防焰性能應符合之規定，下列何者錯誤？', '["地毯等地坪舖設物類，餘焰時間不得超過20秒", "展示用廣告板，餘燃時間不得超過30秒", "厚纖維製品，碳化面積不得超過40平方公分", "地毯等地坪舖設物類，碳化距離不得超過20公分"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
