  ('fire-eq-tech-moex-03198', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備設置標準」規定，電影片映演場所放映室及電氣設備使用之處所，每多少平 方公尺（含未滿）另設一滅火器？', '["50", "100", "150", "200"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03199', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備設置標準」規定，二氧化碳滅火設備採全區放射方式，於電信機械室設置時， 應於多少時間內全部放射完畢？', '["30秒", "1分鐘", "2分鐘", "3.5分鐘"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
